"use client";

import React, { useState } from "react";
import { 
  LayoutDashboard, Plus, Trash2, Edit, DollarSign, 
  PackageCheck, ArrowLeft, X, TrendingUp, AlertTriangle, 
  Users, ShoppingBag
} from "lucide-react";
import Link from "next/link";
import { useProducts } from "@/lib/ProductContext"; 

export default function AdminPage() {
  const { products, addProduct, deleteProduct } = useProducts(); 
  const [showModal, setShowModal] = useState(false);
  const [newProduct, setNewProduct] = useState({ 
    name: "", category: "skincare", price: 0, image: "" 
  });

  // --- ESTATÍSTICAS DINÂMICAS ---
  const totalStockValue = products.reduce((acc, p) => acc + (Number(p.price) || 0), 0);
  const avgPrice = products.length > 0 ? totalStockValue / products.length : 0;
  
  const getCategoryPercentage = (cat: string) => {
    if (products.length === 0) return 0;
    const count = products.filter(p => p.category === cat).length;
    return Math.round((count / products.length) * 100);
  };

  const handleAddProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || newProduct.price <= 0 || !newProduct.image) {
      alert("Por favor, preencha todos os campos!"); 
      return;
    }
    
    addProduct({ 
      ...newProduct, 
      price: Number(newProduct.price), 
      badge: "Novo" 
    });

    setNewProduct({ name: "", category: "skincare", price: 0, image: "" });
    setShowModal(false); 
  };

  const handleDelete = (id: number) => {
    if(confirm("Tem certeza que deseja eliminar este produto?")) {
      deleteProduct(id);
    }
  };

  return (
    <div className="min-h-screen bg-[#F8F9FB] flex font-sans text-black">
      {/* SIDEBAR CORRIGIDA */}
      <aside className="w-20 lg:w-64 bg-white border-r border-gray-100 p-6 hidden md:block sticky top-0 h-screen">
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-8 h-8 bg-[#9C7C50] rounded-lg rotate-3 shadow-lg flex items-center justify-center text-white font-black">N</div>
          <h2 className="text-xl font-black italic text-gray-800 hidden lg:block tracking-tighter">Nani Panel</h2>
        </div>
        
        <nav className="space-y-2">
          {/* Rota corrigida para /dashboard */}
          <Link href="/dashboard" className="flex items-center gap-3 bg-[#9C7C50]/10 text-[#9C7C50] p-4 rounded-2xl transition-all">
            <LayoutDashboard size={20} />
            <span className="font-bold text-xs hidden lg:block uppercase tracking-widest">Dashboard</span>
          </Link>
          
          {/* Rota corrigida para /orders */}
          <Link href="/orders" className="flex items-center gap-3 text-gray-400 p-4 rounded-2xl hover:bg-gray-50 transition-all group">
            <ShoppingBag size={20} className="group-hover:text-[#9C7C50]" />
            <span className="font-bold text-xs hidden lg:block uppercase tracking-widest group-hover:text-gray-700">Pedidos</span>
          </Link>
        </nav>
      </aside>

      {/* CONTEÚDO PRINCIPAL */}
      <main className="flex-1 p-6 lg:p-10">
        <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-10">
          <div>
            <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inventário</h1>
            <p className="text-gray-400 text-sm font-medium">Controle os seus produtos e visualize o desempenho.</p>
          </div>
          <div className="flex gap-3">
            <Link href="/products" className="flex items-center gap-2 bg-white border border-gray-200 px-6 py-3 rounded-2xl font-bold text-[10px] uppercase tracking-widest hover:shadow-md transition-all">
              <ArrowLeft size={14} /> Ver Loja
            </Link>
            <button 
              onClick={() => setShowModal(true)} 
              className="flex items-center gap-2 bg-[#9C7C50] text-white px-6 py-3 rounded-2xl font-bold text-[10px] uppercase tracking-widest shadow-xl shadow-[#9C7C50]/30 hover:scale-105 active:scale-95 transition-all"
            >
              <Plus size={14} /> Novo Produto
            </button>
          </div>
        </header>

        {/* ESTATÍSTICAS */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
          <StatCard title="Valor Stock" value={`AOA ${totalStockValue.toLocaleString()}`} icon={<DollarSign size={20} className="text-green-500" />} trend="+12%" color="green" />
          <StatCard title="Itens Ativos" value={products.length.toString()} icon={<PackageCheck size={20} className="text-blue-500" />} trend="Atualizado" color="blue" />
          <StatCard title="Preço Médio" value={`AOA ${avgPrice.toFixed(0)}`} icon={<TrendingUp size={20} className="text-purple-500" />} trend="Mercado" color="purple" />
          <StatCard title="Clientes" value="1,240" icon={<Users size={20} className="text-[#9C7C50]" />} trend="+24%" color="gold" />
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
          {/* TABELA */}
          <div className="xl:col-span-2 bg-white rounded-[40px] shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-50 bg-white">
              <h3 className="font-black text-xs text-gray-400 uppercase tracking-[0.2em]">Catálogo Ativo</h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  <tr>
                    <th className="p-6">Produto</th>
                    <th className="p-6">Preço</th>
                    <th className="p-6 text-center">Gestão</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {products.map((product) => (
                    <tr key={product.id} className="hover:bg-gray-50/30 transition-colors group">
                      <td className="p-6">
                        <div className="flex items-center gap-4">
                          <img src={product.image} className="w-14 h-14 rounded-2xl object-cover shadow-sm group-hover:scale-110 transition-transform" alt="" />
                          <div>
                            <p className="font-bold text-gray-800 text-sm">{product.name}</p>
                            <p className="text-[10px] text-gray-400 font-black uppercase tracking-tighter">{product.category}</p>
                          </div>
                        </div>
                      </td>
                      <td className="p-6 font-black text-gray-900 text-sm">AOA {product.price.toLocaleString()}</td>
                      <td className="p-6">
                        <div className="flex justify-center gap-2">
                          <button onClick={() => handleDelete(product.id)} className="p-3 text-gray-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* SIDE INSIGHTS */}
          <div className="space-y-8">
            <div className="bg-[#FFF4F2] p-8 rounded-[40px] border border-red-50">
              <div className="flex items-center gap-3 mb-6 text-red-600">
                <AlertTriangle size={20} />
                <h3 className="font-black uppercase text-[10px] tracking-widest">Alertas</h3>
              </div>
              <div className="space-y-4">
                {products.slice(0, 2).map(p => (
                  <div key={p.id} className="bg-white/60 p-4 rounded-2xl flex justify-between items-center border border-red-100/50">
                    <span className="text-xs font-bold text-gray-700 truncate mr-2">{p.name}</span>
                    <span className="text-[9px] font-black text-red-500 bg-red-100 px-2 py-1 rounded-lg shrink-0">BAIXO</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm">
              <h3 className="font-black uppercase text-[10px] tracking-widest text-gray-400 mb-8">Mix por Categoria</h3>
              <div className="space-y-6">
                <CategoryBar label="Skincare" percentage={getCategoryPercentage('skincare')} color="#9C7C50" />
                <CategoryBar label="Maquilhagem" percentage={getCategoryPercentage('makeup')} color="#E5C185" />
                <CategoryBar label="Fragrâncias" percentage={getCategoryPercentage('fragrance')} color="#D1D5DB" />
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* MODAL */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[40px] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">Adicionar Item</h2>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-full transition-all text-gray-400"><X /></button>
            </div>
            <form onSubmit={handleAddProduct} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Nome</label>
                <input required type="text" className="w-full p-4 bg-gray-50 border-none rounded-2xl text-sm outline-none" placeholder="Ex: Creme Hidratante" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Preço (AOA)</label>
                  <input required type="number" className="w-full p-4 bg-gray-50 border-none rounded-2xl text-sm outline-none" value={newProduct.price || ''} onChange={e => setNewProduct({...newProduct, price: Number(e.target.value)})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Categoria</label>
                  <select className="w-full p-4 bg-gray-50 border-none rounded-2xl text-sm outline-none" value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>
                    <option value="skincare">Skincare</option>
                    <option value="makeup">Makeup</option>
                    <option value="fragrance">Perfumes</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Link Imagem</label>
                <input required type="text" className="w-full p-4 bg-gray-50 border-none rounded-2xl text-sm outline-none" placeholder="https://..." value={newProduct.image} onChange={e => setNewProduct({...newProduct, image: e.target.value})} />
              </div>
              <button type="submit" className="w-full bg-[#9C7C50] text-white py-5 rounded-3xl font-black uppercase tracking-widest shadow-xl shadow-[#9C7C50]/20 hover:scale-[1.02] active:scale-95 transition-all">
                Salvar Produto
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

// COMPONENTES AUXILIARES
function StatCard({ title, value, icon, trend, color }: any) {
  const colorMap: any = {
    green: "bg-green-50 text-green-600",
    blue: "bg-blue-50 text-blue-600",
    purple: "bg-purple-50 text-purple-600",
    gold: "bg-[#9C7C50]/10 text-[#9C7C50]"
  };

  return (
    <div className="bg-white p-7 rounded-[40px] shadow-sm border border-gray-50">
      <div className="flex justify-between items-start mb-5">
        <div className={`p-4 rounded-2xl bg-gray-50`}>{icon}</div>
        <span className={`text-[9px] font-black px-3 py-1.5 rounded-full ${colorMap[color]}`}>{trend}</span>
      </div>
      <p className="text-gray-400 font-bold text-[10px] uppercase tracking-[0.15em] mb-1">{title}</p>
      <p className="text-2xl font-black text-gray-900">{value}</p>
    </div>
  );
}

function CategoryBar({ label, percentage, color }: any) {
  return (
    <div className="space-y-3">
      <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
        <span className="text-gray-500">{label}</span>
        <span className="text-gray-900">{percentage}%</span>
      </div>
      <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
        <div className="h-full transition-all duration-1000" style={{ width: `${percentage}%`, backgroundColor: color }}></div>
      </div>
    </div>
  );
}